#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool wordBreak(string s, vector<string>& wordDict) {
        int n = s.size();
        vector<bool> dp(n + 1, false);
        dp[0] = true;
        for (int i = 0; i <= n; i++) {
            if (dp[i]) {
                for (const string& word : wordDict) {
                    if (i + word.size() <= n && s.substr(i, word.size()) == word) {
                        dp[i + word.size()] = true;
                    }
                }
            }
        }
        return dp[n];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s;
    if (!(cin >> s)) return 0;
    int n;
    if (!(cin >> n)) return 0;
    vector<string> wordDict(n);
    for (int i = 0; i < n; i++) {
        if (!(cin >> wordDict[i])) return 0;
    }
    Solution sol;
    bool ans = sol.wordBreak(s, wordDict);
    cout << boolalpha << ans << endl;
    return 0;
}
